{"code":"import json, re, pandas as pd

def parse_stars(text):
    if text is None:
        return None
    m = re.search(r"([0-9][0-9,]*)\s+stars", text)
    if not m:
        return None
    return int(m.group(1).replace(',', ''))

def parse_repo(text):
    if text is None:
        return None
    m = re.search(r"project\s+([^\s]+/[^\s]+)", text)
    if m:
        return m.group(1).rstrip('.')
    m = re.search(r"The project\s+([^\s]+/[^\s]+)", text)
    if m:
        return m.group(1).rstrip('.')
    return None

# Step 1: latest release per NPM package based on VersionInfo.IsRelease=true and max Ordinal
sql_latest = """
WITH rel AS (
  SELECT Name, Version,
         CAST(json_extract(VersionInfo, '$.Ordinal') AS BIGINT) AS Ordinal
  FROM packageinfo
  WHERE System='NPM'
    AND CAST(json_extract(VersionInfo, '$.IsRelease') AS BOOLEAN)=true
), mx AS (
  SELECT Name, MAX(Ordinal) AS max_ord
  FROM rel
  GROUP BY Name
)
SELECT r.Name, r.Version
FROM rel r
JOIN mx ON mx.Name=r.Name AND mx.max_ord=r.Ordinal
"""

print('__RESULT__:')
print(json.dumps({'sql_latest': sql_latest}))"}

